# api_routes.py - HELA SMART SACCO
# PORTAL_HTML is used by server.py (pure stdlib server, no fastapi needed)
# If fastapi IS installed, build_app() also provides a fastapi ASGI app.

PORTAL_HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1,viewport-fit=cover">\n<meta name="theme-color" content="#0d5c30">\n<title>HELA SMART SACCO</title>\n<style>\n:root{\n  --g:#0d5c30;--gd:#07361c;--gm:#1a8a47;--gl:#e6f4ec;--g2:#52c27a;\n  --r:#dc2626;--o:#d97706;--b:#2563eb;--pu:#7c3aed;\n  --bg:#f0f4f1;--card:#fff;--text:#111827;--muted:#6b7280;\n  --border:#e5e7eb;--radius:16px;--sh:0 1px 8px rgba(0,0,0,.08);\n}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\nbody{background:var(--bg);color:var(--text);font-family:\'Segoe UI\',system-ui,-apple-system,sans-serif;\n     min-height:100vh;overscroll-behavior:none}\n\n/* ── AUTH SCREENS ── */\n.auth-wrap{min-height:100vh;display:flex;flex-direction:column;\n           background:linear-gradient(160deg,var(--gd) 0%,var(--g) 55%,var(--gm) 100%)}\n.auth-hero{flex:0 0 auto;padding:48px 24px 32px;text-align:center;color:#fff}\n.auth-logo{width:76px;height:76px;border-radius:24px;background:rgba(255,255,255,.15);\n           backdrop-filter:blur(10px);display:inline-flex;align-items:center;\n           justify-content:center;font-size:36px;margin-bottom:16px;\n           border:2px solid rgba(255,255,255,.25)}\n.auth-hero h1{font-size:26px;font-weight:800;letter-spacing:-.5px;margin-bottom:4px}\n.auth-hero p{font-size:14px;opacity:.75}\n.auth-card{flex:1;background:#fff;border-radius:28px 28px 0 0;padding:28px 24px 40px;\n           overflow-y:auto}\n.auth-tabs{display:flex;gap:4px;background:var(--bg);border-radius:12px;padding:4px;\n           margin-bottom:24px}\n.auth-tab{flex:1;padding:10px;border:none;background:none;border-radius:9px;font-size:14px;\n          font-weight:600;color:var(--muted);cursor:pointer;transition:all .2s}\n.auth-tab.active{background:#fff;color:var(--g);box-shadow:var(--sh)}\n.field{margin-bottom:16px}\n.field label{display:block;font-size:12px;font-weight:700;color:var(--muted);\n             text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px}\n.field input,.field select{\n  width:100%;padding:14px 16px;border:2px solid var(--border);border-radius:12px;\n  font-size:15px;color:var(--text);outline:none;background:#fff;\n  transition:border-color .2s,box-shadow .2s;appearance:none}\n.field input:focus,.field select:focus{border-color:var(--g);\n  box-shadow:0 0 0 3px rgba(13,92,48,.1)}\n.field-row{display:grid;grid-template-columns:1fr 1fr;gap:12px}\n.btn{width:100%;padding:16px;border:none;border-radius:14px;font-size:16px;font-weight:700;\n     cursor:pointer;transition:all .2s;letter-spacing:.2px}\n.btn-g{background:linear-gradient(135deg,var(--gm),var(--gd));color:#fff;\n       box-shadow:0 4px 16px rgba(13,92,48,.35)}\n.btn-g:active{transform:scale(.98)}\n.btn-g:disabled{opacity:.6;cursor:not-allowed;transform:none}\n.btn-outline{background:none;border:2px solid var(--border);color:var(--muted);\n             padding:14px;font-size:14px}\n.errmsg{background:#fef2f2;color:var(--r);padding:12px 16px;border-radius:10px;\n        font-size:13px;margin-bottom:16px;display:none;border:1px solid #fee2e2}\n.sucmsg{background:#f0fdf4;color:var(--g);padding:12px 16px;border-radius:10px;\n        font-size:13px;margin-bottom:16px;display:none;border:1px solid #bbf7d0}\n.divider{display:flex;align-items:center;gap:12px;margin:20px 0;color:var(--muted);font-size:13px}\n.divider::before,.divider::after{content:\'\';flex:1;height:1px;background:var(--border)}\n.forgot{text-align:center;margin-top:16px;font-size:13px;color:var(--muted)}\n.forgot a{color:var(--g);font-weight:600;text-decoration:none}\n.pw-wrap{position:relative}\n.pw-toggle{position:absolute;right:14px;top:50%;transform:translateY(-50%);\n           background:none;border:none;cursor:pointer;font-size:18px;padding:4px}\n.strength{height:4px;border-radius:2px;margin-top:6px;transition:all .3s;background:var(--border)}\n.strength.weak{background:var(--r);width:30%}\n.strength.fair{background:var(--o);width:60%}\n.strength.strong{background:var(--g);width:100%}\n\n/* ── APP SHELL ── */\n#app{display:none;flex-direction:column;min-height:100vh}\n.topbar{background:linear-gradient(90deg,var(--gd),var(--g));color:#fff;\n        height:60px;display:flex;align-items:center;padding:0 16px;gap:12px;\n        position:sticky;top:0;z-index:100;box-shadow:0 2px 12px rgba(0,0,0,.2)}\n.tb-avatar{width:36px;height:36px;border-radius:50%;background:rgba(255,255,255,.2);\n           display:flex;align-items:center;justify-content:center;\n           font-size:15px;font-weight:700;flex-shrink:0;border:2px solid rgba(255,255,255,.3)}\n.tb-info{flex:1;min-width:0}\n.tb-name{font-size:15px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.tb-sub{font-size:11px;opacity:.75}\n.tb-btn{background:rgba(255,255,255,.15);border:1px solid rgba(255,255,255,.25);\n        color:#fff;padding:7px 14px;border-radius:20px;font-size:12px;font-weight:600;cursor:pointer}\n.pc{padding:16px;max-width:560px;margin:0 auto;width:100%;flex:1;padding-bottom:90px}\n\n/* ── BOTTOM NAV ── */\n.bnav{position:fixed;bottom:0;left:0;right:0;background:#fff;\n      border-top:1px solid var(--border);display:flex;\n      box-shadow:0 -4px 20px rgba(0,0,0,.08);\n      padding-bottom:env(safe-area-inset-bottom)}\n.ni{flex:1;padding:10px 2px 8px;display:flex;flex-direction:column;align-items:center;\n    gap:3px;cursor:pointer;border:none;background:none;color:var(--muted);\n    font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.3px;transition:all .15s}\n.ni .ic{font-size:24px;line-height:1;transition:transform .2s}\n.ni.active{color:var(--g)}\n.ni.active .ic{transform:scale(1.2)}\n\n/* ── CARDS ── */\n.card{background:var(--card);border-radius:var(--radius);padding:18px;\n      box-shadow:var(--sh);margin-bottom:14px}\n.card-title{font-size:11px;font-weight:700;color:var(--muted);text-transform:uppercase;\n            letter-spacing:.6px;margin-bottom:12px}\n\n/* ── BALANCE HERO ── */\n.bh{background:linear-gradient(135deg,var(--g) 0%,var(--gd) 100%);\n    border-radius:20px;padding:24px 20px;color:#fff;margin-bottom:16px;\n    box-shadow:0 8px 32px rgba(13,92,48,.3);position:relative;overflow:hidden}\n.bh::before{content:\'\';position:absolute;top:-30px;right:-30px;width:140px;height:140px;\n            border-radius:50%;background:rgba(255,255,255,.06)}\n.bh::after{content:\'\';position:absolute;bottom:-20px;left:-20px;width:100px;height:100px;\n           border-radius:50%;background:rgba(255,255,255,.04)}\n.bh-label{font-size:12px;opacity:.75;margin-bottom:6px;font-weight:600;letter-spacing:.3px;\n          text-transform:uppercase}\n.bh-amount{font-size:38px;font-weight:800;letter-spacing:-1.5px;line-height:1}\n.bh-acc{font-size:12px;opacity:.65;margin-top:6px}\n.bh-row{display:flex;justify-content:space-between;align-items:flex-end;margin-top:16px;\n        padding-top:14px;border-top:1px solid rgba(255,255,255,.15)}\n.bh-stat{text-align:center}\n.bh-stat-val{font-size:18px;font-weight:700}\n.bh-stat-lbl{font-size:10px;opacity:.65;text-transform:uppercase;letter-spacing:.3px}\n\n/* ── QUICK ACTIONS ── */\n.qa-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px}\n.qa{background:#fff;border:none;border-radius:14px;padding:14px 6px;\n    display:flex;flex-direction:column;align-items:center;gap:6px;cursor:pointer;\n    box-shadow:var(--sh);transition:all .2s;text-decoration:none}\n.qa:active{transform:scale(.94)}\n.qa .qi{width:44px;height:44px;border-radius:12px;display:flex;align-items:center;\n        justify-content:center;font-size:20px;margin-bottom:2px}\n.qa span{font-size:10px;font-weight:700;color:var(--muted);text-align:center;letter-spacing:.2px}\n\n/* ── TRANSACTIONS ── */\n.txn{display:flex;align-items:center;padding:13px 0;\n     border-bottom:1px solid var(--border);gap:12px}\n.txn:last-child{border-bottom:none}\n.txn-ic{width:42px;height:42px;border-radius:13px;display:flex;align-items:center;\n        justify-content:center;font-size:18px;flex-shrink:0}\n.txn-ic.cr{background:#e6f4ec}\n.txn-ic.db{background:#fef2f2}\n.txn-ic.tr{background:#eff6ff}\n.txn-body{flex:1;min-width:0}\n.txn-desc{font-size:14px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.txn-meta{font-size:11px;color:var(--muted);margin-top:2px}\n.txn-right{text-align:right;flex-shrink:0}\n.txn-amt{font-size:14px;font-weight:700}\n.txn-amt.cr{color:var(--g)}\n.txn-amt.db{color:var(--r)}\n.txn-bal{font-size:11px;color:var(--muted);margin-top:1px}\n\n/* ── LOANS ── */\n.loan-card{background:#fff;border-radius:14px;padding:18px;box-shadow:var(--sh);\n           margin-bottom:12px;border-left:4px solid var(--g)}\n.loan-card.overdue{border-color:var(--r)}\n.loan-card.pending{border-color:var(--o)}\n.lrow{display:flex;justify-content:space-between;align-items:center;padding:5px 0}\n.ll{font-size:12px;color:var(--muted)}\n.lv{font-size:13px;font-weight:700}\n.prog{height:6px;background:var(--border);border-radius:3px;margin:12px 0 8px}\n.progf{height:100%;border-radius:3px;transition:width .6s;\n       background:linear-gradient(90deg,var(--gm),var(--g2))}\n.badge{display:inline-flex;align-items:center;gap:4px;padding:3px 10px;\n       border-radius:20px;font-size:11px;font-weight:700;letter-spacing:.2px}\n.badge.active{background:#e6f4ec;color:var(--g)}\n.badge.overdue{background:#fef2f2;color:var(--r)}\n.badge.pending{background:#fffbeb;color:var(--o)}\n.badge.paid,.badge.completed,.badge.disbursed{background:#eff6ff;color:var(--b)}\n\n/* ── MODALS ── */\n.mo{position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:200;\n    display:none;align-items:flex-end;justify-content:center;backdrop-filter:blur(4px)}\n.mo.open{display:flex;animation:fadeIn .2s}\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n.ms{background:#fff;border-radius:24px 24px 0 0;padding:0 24px 40px;\n    width:100%;max-width:520px;max-height:90vh;overflow-y:auto;\n    animation:slideUp .3s cubic-bezier(.32,1,.36,1)}\n@keyframes slideUp{from{transform:translateY(60px)}to{transform:translateY(0)}}\n.ms-handle{width:44px;height:5px;background:var(--border);border-radius:3px;\n           margin:14px auto 20px}\n.ms-title{font-size:20px;font-weight:800;margin-bottom:6px}\n.ms-sub{font-size:13px;color:var(--muted);margin-bottom:20px}\n.presets{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:18px}\n.preset{padding:9px 16px;border:2px solid var(--border);border-radius:20px;\n        background:none;font-size:13px;font-weight:600;cursor:pointer;\n        transition:all .15s;color:var(--muted)}\n.preset:hover,.preset.sel{border-color:var(--g);background:var(--gl);color:var(--g)}\n.calc-box{background:var(--gl);border-radius:12px;padding:14px;margin-bottom:16px;\n          border:1px solid rgba(13,92,48,.15);display:none}\n.calc-box strong{color:var(--g)}\n.mb{width:100%;padding:16px;border:none;border-radius:14px;font-size:15px;\n    font-weight:700;cursor:pointer;transition:all .2s;margin-top:8px}\n.mb.green{background:linear-gradient(135deg,var(--gm),var(--gd));color:#fff;\n          box-shadow:0 4px 14px rgba(13,92,48,.3)}\n.mb.grey{background:var(--bg);color:var(--muted)}\n\n/* ── PROFILE ── */\n.pav{width:80px;height:80px;border-radius:50%;\n     background:linear-gradient(135deg,var(--gm),var(--gd));\n     display:flex;align-items:center;justify-content:center;\n     font-size:30px;font-weight:800;color:#fff;margin:0 auto 12px;\n     box-shadow:0 4px 16px rgba(13,92,48,.3)}\n.kyc-v{background:#e6f4ec;color:var(--g);padding:4px 12px;border-radius:20px;\n       font-size:12px;font-weight:700}\n.kyc-p{background:#fffbeb;color:var(--o);padding:4px 12px;border-radius:20px;\n       font-size:12px;font-weight:700}\n.info-row{display:flex;align-items:center;padding:13px 0;border-bottom:1px solid var(--border)}\n.info-row:last-child{border-bottom:none}\n.il{font-size:12px;color:var(--muted);width:120px;flex-shrink:0;font-weight:600}\n.iv{font-size:14px;font-weight:600}\n\n/* ── MISC ── */\n.section-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}\n.sh-title{font-size:17px;font-weight:800}\n.sh-action{font-size:13px;color:var(--g);font-weight:700;cursor:pointer}\n.empty{text-align:center;padding:48px 20px;color:var(--muted)}\n.empty-ic{font-size:52px;margin-bottom:14px;display:block}\n.empty h3{font-size:17px;font-weight:700;color:var(--text);margin-bottom:6px}\n.empty p{font-size:13px;line-height:1.5}\n.sp{width:36px;height:36px;border:3px solid var(--border);\n    border-top-color:var(--g);border-radius:50%;animation:spin .7s linear infinite;margin:48px auto}\n@keyframes spin{to{transform:rotate(360deg)}}\n.toast{position:fixed;bottom:90px;left:50%;transform:translateX(-50%);\n       padding:12px 22px;border-radius:30px;font-size:14px;font-weight:600;\n       z-index:500;opacity:0;transition:opacity .3s;pointer-events:none;\n       max-width:90vw;text-align:center;white-space:nowrap;overflow:hidden;\n       text-overflow:ellipsis}\n.toast.show{opacity:1}\n.toast.ok{background:#0d5c30;color:#fff}\n.toast.err{background:#dc2626;color:#fff}\n.toast.info{background:#1a1a2e;color:#fff}\n.alert{border-radius:14px;padding:14px 16px;margin-bottom:14px;display:flex;gap:12px;align-items:flex-start}\n.alert.warn{background:#fffbeb;border:1px solid #fde68a}\n.alert.danger{background:#fef2f2;border:1px solid #fecaca}\n.alert-icon{font-size:20px;flex-shrink:0;margin-top:2px}\n.alert-body h4{font-size:14px;font-weight:700;margin-bottom:3px}\n.alert-body p{font-size:12px;color:var(--muted);line-height:1.4}\n.chip{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;\n      border-radius:20px;font-size:11px;font-weight:700;background:var(--gl);color:var(--g)}\n</style>\n</head>\n<body>\n\n<!-- ═══ AUTH SCREENS ══════════════════════════════════════════════════════════ -->\n<div id="auth" class="auth-wrap">\n  <div class="auth-hero">\n    <div class="auth-logo">🏦</div>\n    <h1>HELA SMART SACCO</h1>\n    <p>Your savings, your future</p>\n  </div>\n  <div class="auth-card">\n    <div class="auth-tabs">\n      <button class="auth-tab active" id="tab-login"    onclick="switchTab(\'login\')">Sign In</button>\n      <button class="auth-tab"        id="tab-register" onclick="switchTab(\'register\')">Create Account</button>\n    </div>\n\n    <!-- Login form -->\n    <div id="form-login">\n      <div class="errmsg" id="login-err"></div>\n      <div class="field">\n        <label>Phone Number or Username</label>\n        <input type="tel" id="l-phone" placeholder="07XX XXX XXX" autocomplete="tel" inputmode="tel">\n      </div>\n      <div class="field">\n        <label>Password</label>\n        <div class="pw-wrap">\n          <input type="password" id="l-pass" placeholder="Enter your password" autocomplete="current-password">\n          <button class="pw-toggle" onclick="togglePw(\'l-pass\',this)" tabindex="-1">👁</button>\n        </div>\n      </div>\n      <button class="btn btn-g" id="login-btn" onclick="doLogin()">Sign In</button>\n      <p class="forgot"><a href="#" onclick="return false">Forgot password?</a> Contact your branch</p>\n    </div>\n\n    <!-- Register form -->\n    <div id="form-register" style="display:none">\n      <div class="errmsg" id="reg-err"></div>\n      <div class="sucmsg" id="reg-ok"></div>\n      <div class="field-row">\n        <div class="field">\n          <label>First Name</label>\n          <input type="text" id="r-first" placeholder="e.g. Jane" autocomplete="given-name">\n        </div>\n        <div class="field">\n          <label>Last Name</label>\n          <input type="text" id="r-last" placeholder="e.g. Wanjiku" autocomplete="family-name">\n        </div>\n      </div>\n      <div class="field">\n        <label>Phone Number (M-Pesa)</label>\n        <input type="tel" id="r-phone" placeholder="07XX XXX XXX" inputmode="tel">\n      </div>\n      <div class="field">\n        <label>National ID Number</label>\n        <input type="text" id="r-id" placeholder="e.g. 12345678" inputmode="numeric">\n      </div>\n      <div class="field">\n        <label>Email Address (optional)</label>\n        <input type="email" id="r-email" placeholder="jane@example.com" autocomplete="email">\n      </div>\n      <div class="field">\n        <label>Password</label>\n        <div class="pw-wrap">\n          <input type="password" id="r-pass" placeholder="Minimum 6 characters" oninput="checkStrength(this)">\n          <button class="pw-toggle" onclick="togglePw(\'r-pass\',this)" tabindex="-1">👁</button>\n        </div>\n        <div class="strength" id="strength-bar"></div>\n      </div>\n      <div class="field">\n        <label>Confirm Password</label>\n        <div class="pw-wrap">\n          <input type="password" id="r-pass2" placeholder="Re-enter password">\n        </div>\n      </div>\n      <button class="btn btn-g" id="reg-btn" onclick="doRegister()">Create My Account</button>\n      <p style="font-size:12px;color:var(--muted);text-align:center;margin-top:14px;line-height:1.5">\n        By registering you agree to HELA SACCO\'s terms. KYC verification will be completed at the branch.\n      </p>\n    </div>\n  </div>\n</div>\n\n<!-- ═══ APP ═══════════════════════════════════════════════════════════════════ -->\n<div id="app">\n  <div class="topbar">\n    <div class="tb-avatar" id="tb-av">H</div>\n    <div class="tb-info">\n      <div class="tb-name" id="tb-name">Member</div>\n      <div class="tb-sub" id="tb-sub">HELA SMART SACCO</div>\n    </div>\n    <button class="tb-btn" onclick="doLogout()">Logout</button>\n  </div>\n  <div class="pc" id="pc"></div>\n  <nav class="bnav">\n    <button class="ni active" id="nav-home"      onclick="go(\'home\')">\n      <span class="ic">🏠</span>Home</button>\n    <button class="ni"        id="nav-statement" onclick="go(\'statement\')">\n      <span class="ic">📄</span>Statement</button>\n    <button class="ni"        id="nav-loans"     onclick="go(\'loans\')">\n      <span class="ic">💳</span>Loans</button>\n    <button class="ni"        id="nav-invest"    onclick="go(\'investments\')">\n      <span class="ic">📈</span>Invest</button>\n    <button class="ni"        id="nav-profile"   onclick="go(\'profile\')">\n      <span class="ic">👤</span>Profile</button>\n  </nav>\n</div>\n\n<!-- DEPOSIT MODAL -->\n<div class="mo" id="dep-mo">\n  <div class="ms">\n    <div class="ms-handle"></div>\n    <div class="ms-title">💳 Deposit via M-Pesa</div>\n    <div class="ms-sub">Enter amount and your M-Pesa number. A payment prompt will appear on your phone.</div>\n    <div class="presets">\n      <button class="preset" onclick="setAmt(this,500)">KSh 500</button>\n      <button class="preset" onclick="setAmt(this,1000)">KSh 1,000</button>\n      <button class="preset" onclick="setAmt(this,2000)">KSh 2,000</button>\n      <button class="preset" onclick="setAmt(this,5000)">KSh 5,000</button>\n      <button class="preset" onclick="setAmt(this,10000)">KSh 10,000</button>\n    </div>\n    <div class="field"><label>Amount (KSh)</label>\n      <input type="number" id="da" placeholder="Enter amount" min="10" inputmode="numeric"></div>\n    <div class="field"><label>M-Pesa Phone Number</label>\n      <input type="tel" id="dp" placeholder="07XX XXX XXX" inputmode="tel"></div>\n    <button class="mb green" onclick="submitDeposit()">📱 Send STK Push to Phone</button>\n    <button class="mb grey"  onclick="closeMo()">Cancel</button>\n  </div>\n</div>\n\n<!-- LOAN MODAL -->\n<div class="mo" id="loan-mo">\n  <div class="ms">\n    <div class="ms-handle"></div>\n    <div class="ms-title">💵 Apply for a Loan</div>\n    <div class="ms-sub">Fill in the details below. Admin will review within 24 hours.</div>\n    <div class="field"><label>Loan Amount (KSh)</label>\n      <input type="number" id="la" placeholder="e.g. 50,000" min="1000" inputmode="numeric" oninput="calcLoan()"></div>\n    <div class="field-row">\n      <div class="field"><label>Term (months)</label>\n        <input type="number" id="lt" placeholder="12" min="1" max="60" value="12" inputmode="numeric" oninput="calcLoan()"></div>\n      <div class="field"><label>Interest Rate</label>\n        <select id="lr" onchange="calcLoan()">\n          <option value="1.5">1.5% / month</option>\n          <option value="2.0">2.0% / month</option>\n        </select>\n      </div>\n    </div>\n    <div class="calc-box" id="lcalc">\n      <strong>📊 Loan Summary</strong>\n      <div id="lsum" style="margin-top:8px;font-size:13px;line-height:1.8"></div>\n    </div>\n    <div class="field"><label>Purpose of Loan</label>\n      <input type="text" id="lpu" placeholder="e.g. Business expansion, school fees"></div>\n    <button class="mb green" onclick="submitLoan()">Submit Application</button>\n    <button class="mb grey"  onclick="closeMo()">Cancel</button>\n  </div>\n</div>\n\n<div class="toast" id="toast"></div>\n\n<script>\nlet T=localStorage.getItem(\'ht\')||\'\';\nlet ME=JSON.parse(localStorage.getItem(\'hm\')||\'null\');\n\nasync function api(path,opts={}){\n  const r=await fetch(window.location.origin+path,{\n    headers:{\'Content-Type\':\'application/json\',...(T?{\'Authorization\':\'Bearer \'+T}:{})},\n    ...opts\n  });\n  const d=await r.json().catch(()=>({}));\n  if(!r.ok)throw new Error(d.detail||d.message||\'Request failed (\'+r.status+\')\');\n  return d;\n}\n\n// ── AUTH TAB SWITCH ───────────────────────────────────────────────────────────\nfunction switchTab(tab){\n  [\'login\',\'register\'].forEach(t=>{\n    document.getElementById(\'tab-\'+t).classList.toggle(\'active\',t===tab);\n    document.getElementById(\'form-\'+t).style.display=t===tab?\'block\':\'none\';\n  });\n  clearErrors();\n}\n\nfunction clearErrors(){\n  document.querySelectorAll(\'.errmsg,.sucmsg\').forEach(e=>{\n    e.style.display=\'none\';e.textContent=\'\';\n  });\n}\n\nfunction showErr(id,msg){\n  const e=document.getElementById(id);\n  e.textContent=msg;e.style.display=\'block\';\n  e.scrollIntoView({behavior:\'smooth\',block:\'nearest\'});\n}\n\nfunction showOk(id,msg){\n  const e=document.getElementById(id);\n  e.textContent=msg;e.style.display=\'block\';\n}\n\n// ── PASSWORD UX ───────────────────────────────────────────────────────────────\nfunction togglePw(id,btn){\n  const i=document.getElementById(id);\n  i.type=i.type===\'password\'?\'text\':\'password\';\n  btn.textContent=i.type===\'password\'?\'👁\':\'🙈\';\n}\n\nfunction checkStrength(input){\n  const v=input.value;\n  const bar=document.getElementById(\'strength-bar\');\n  if(!v){bar.className=\'strength\';return;}\n  const score=(v.length>=8?1:0)+(v.length>=12?1:0)+(/[A-Z]/.test(v)?1:0)+\n              (/[0-9]/.test(v)?1:0)+(/[^A-Za-z0-9]/.test(v)?1:0);\n  bar.className=\'strength \'+([\'\',\'weak\',\'weak\',\'fair\',\'fair\',\'strong\'][Math.min(score,5)]);\n}\n\n// ── LOGIN ─────────────────────────────────────────────────────────────────────\n// ── DETECT IF OPENED AS FILE (not via server) ─────────────────────────────\nif(window.location.protocol===\'file:\'){\n  document.body.innerHTML=`<div style="min-height:100vh;background:linear-gradient(160deg,#07361c,#0d5c30);\n    display:flex;align-items:center;justify-content:center;padding:24px;font-family:system-ui">\n    <div style="background:#fff;border-radius:24px;padding:32px 28px;max-width:380px;width:100%;text-align:center">\n      <div style="font-size:52px;margin-bottom:16px">⚠️</div>\n      <h2 style="font-size:20px;font-weight:800;color:#111;margin-bottom:10px">Wrong way to open!</h2>\n      <p style="font-size:14px;color:#6b7280;line-height:1.6;margin-bottom:20px">\n        You opened this file directly from your phone storage.<br><br>\n        The portal only works when opened via the HELA SACCO app server.\n      </p>\n      <div style="background:#f0f4f1;border-radius:14px;padding:16px;margin-bottom:20px;text-align:left">\n        <div style="font-size:12px;font-weight:700;color:#0d5c30;margin-bottom:8px">HOW TO ACCESS:</div>\n        <div style="font-size:14px;font-weight:700;color:#111;margin-bottom:4px">Step 1</div>\n        <div style="font-size:13px;color:#6b7280;margin-bottom:12px">Open the HELA SACCO app on this phone — the server starts automatically.</div>\n        <div style="font-size:14px;font-weight:700;color:#111;margin-bottom:4px">Step 2</div>\n        <div style="font-size:13px;color:#6b7280;margin-bottom:12px">Open a new browser tab.</div>\n        <div style="font-size:14px;font-weight:700;color:#111;margin-bottom:4px">Step 3</div>\n        <div style="font-size:13px;color:#6b7280">Type this address in the address bar:</div>\n        <div style="background:#0d5c30;color:#fff;padding:10px 14px;border-radius:10px;\n             font-size:16px;font-weight:800;font-family:monospace;margin-top:8px;letter-spacing:.5px">\n          localhost:8080\n        </div>\n      </div>\n      <p style="font-size:12px;color:#9ca3af">\n        Members on the same WiFi can use your phone\'s IP address instead.<br>\n        For internet access, set up a Cloudflare tunnel.\n      </p>\n    </div>\n  </div>`;\n}\n\ndocument.addEventListener(\'DOMContentLoaded\',()=>{\n  document.getElementById(\'l-pass\').addEventListener(\'keydown\',e=>{if(e.key===\'Enter\')doLogin();});\n  const saved=localStorage.getItem(\'hlp\');\n  if(saved)document.getElementById(\'l-phone\').value=saved;\n  document.getElementById(\'l-phone\').addEventListener(\'change\',e=>localStorage.setItem(\'hlp\',e.target.value));\n  if(T&&ME)showApp();\n});\n\nasync function doLogin(){\n  clearErrors();\n  const phone=document.getElementById(\'l-phone\').value.trim();\n  const pass=document.getElementById(\'l-pass\').value;\n  if(!phone){showErr(\'login-err\',\'Please enter your phone number\');return;}\n  if(!pass){showErr(\'login-err\',\'Please enter your password\');return;}\n  const btn=document.getElementById(\'login-btn\');\n  btn.disabled=true;btn.textContent=\'Signing in…\';\n  try{\n    const res=await api(\'/api/auth/login\',{method:\'POST\',body:JSON.stringify({phone,password:pass})});\n    T=res.token;localStorage.setItem(\'ht\',T);\n    await loadMe();showApp();\n  }catch(e){showErr(\'login-err\',e.message);}\n  finally{btn.disabled=false;btn.textContent=\'Sign In\';}\n}\n\n// ── REGISTER ──────────────────────────────────────────────────────────────────\nasync function doRegister(){\n  clearErrors();\n  const first=document.getElementById(\'r-first\').value.trim();\n  const last=document.getElementById(\'r-last\').value.trim();\n  const phone=document.getElementById(\'r-phone\').value.trim();\n  const id_num=document.getElementById(\'r-id\').value.trim();\n  const email=document.getElementById(\'r-email\').value.trim();\n  const pass=document.getElementById(\'r-pass\').value;\n  const pass2=document.getElementById(\'r-pass2\').value;\n  if(!first||!last){showErr(\'reg-err\',\'Please enter your full name\');return;}\n  if(!phone){showErr(\'reg-err\',\'Phone number is required\');return;}\n  if(!id_num){showErr(\'reg-err\',\'National ID number is required\');return;}\n  if(!pass||pass.length<6){showErr(\'reg-err\',\'Password must be at least 6 characters\');return;}\n  if(pass!==pass2){showErr(\'reg-err\',\'Passwords do not match\');return;}\n  const btn=document.getElementById(\'reg-btn\');\n  btn.disabled=true;btn.textContent=\'Creating account…\';\n  try{\n    const res=await api(\'/api/auth/register\',{method:\'POST\',body:JSON.stringify({\n      first_name:first,last_name:last,phone,id_number:id_num,email,password:pass\n    })});\n    showOk(\'reg-ok\',\'✅ Account created! Member No: \'+res.member_no+\'. \'+res.message);\n    T=res.token;localStorage.setItem(\'ht\',T);\n    await loadMe();\n    setTimeout(()=>showApp(),2000);\n  }catch(e){showErr(\'reg-err\',e.message);}\n  finally{btn.disabled=false;btn.textContent=\'Create My Account\';}\n}\n\n// ── APP ───────────────────────────────────────────────────────────────────────\nasync function loadMe(){\n  ME=await api(\'/api/me\');\n  localStorage.setItem(\'hm\',JSON.stringify(ME));\n}\n\nfunction showApp(){\n  document.getElementById(\'auth\').style.display=\'none\';\n  document.getElementById(\'app\').style.display=\'flex\';\n  const n=ME?.name||\'Member\';\n  document.getElementById(\'tb-name\').textContent=n;\n  document.getElementById(\'tb-sub\').textContent=ME?.member_no?\'No. \'+ME.member_no:\'Member Portal\';\n  document.getElementById(\'tb-av\').textContent=n.split(\' \').map(w=>w[0]).join(\'\').slice(0,2).toUpperCase();\n  go(\'home\');\n}\n\nfunction doLogout(){\n  T=\'\';ME=null;\n  localStorage.removeItem(\'ht\');localStorage.removeItem(\'hm\');\n  document.getElementById(\'app\').style.display=\'none\';\n  document.getElementById(\'auth\').style.display=\'flex\';\n  document.getElementById(\'l-pass\').value=\'\';\n  clearErrors();\n}\n\nfunction go(page){\n  document.querySelectorAll(\'.ni\').forEach(n=>n.classList.remove(\'active\'));\n  const n=document.getElementById(\'nav-\'+page);if(n)n.classList.add(\'active\');\n  const map={home,statement,loans,investments,profile};\n  (map[page]||home)();\n}\n\n// ── HOME ──────────────────────────────────────────────────────────────────────\nasync function home(){\n  const c=document.getElementById(\'pc\');\n  c.innerHTML=\'<div class="sp"></div>\';\n  try{\n    await loadMe();\n    const m=ME;\n    const bal=(m.balance||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n    const ol=(m.loans||[]).filter(l=>l.status===\'overdue\');\n    const al=(m.loans||[]).filter(l=>[\'active\',\'disbursed\'].includes(l.status));\n    c.innerHTML=`\n      <div class="bh">\n        <div class="bh-label">Total Savings Balance</div>\n        <div class="bh-amount">KSh ${bal}</div>\n        <div class="bh-acc">Acc No: ${m.account_no||\'—\'}</div>\n        <div class="bh-row">\n          <div class="bh-stat"><div class="bh-stat-val">${al.length}</div><div class="bh-stat-lbl">Active Loans</div></div>\n          <div class="bh-stat"><div class="bh-stat-val">${m.kyc_status===\'verified\'?\'✓\':\'⏳\'}</div><div class="bh-stat-lbl">KYC Status</div></div>\n          <div class="bh-stat"><div class="bh-stat-val">${ol.length>0?\'⚠️\':\'✅\'}</div><div class="bh-stat-lbl">Standing</div></div>\n        </div>\n      </div>\n      ${ol.length?`<div class="alert danger"><span class="alert-icon">⚠️</span>\n        <div class="alert-body"><h4>Overdue Loan</h4>\n        <p>Outstanding: KSh ${ol[0].outstanding.toLocaleString(\'en-KE\',{minimumFractionDigits:2})} — please pay urgently to avoid penalties.</p></div></div>`:\'\'}\n      ${m.kyc_status!==\'verified\'?`<div class="alert warn"><span class="alert-icon">🪪</span>\n        <div class="alert-body"><h4>KYC Verification Pending</h4>\n        <p>Visit any branch with your National ID to complete verification and unlock full services.</p></div></div>`:\'\'}\n      <div class="qa-grid">\n        <button class="qa" onclick="openMo(\'dep-mo\')">\n          <div class="qi" style="background:#e6f4ec">💳</div><span>Deposit</span></button>\n        <button class="qa" onclick="openMo(\'loan-mo\')">\n          <div class="qi" style="background:#fffbeb">💵</div><span>Apply Loan</span></button>\n        <button class="qa" onclick="go(\'statement\')">\n          <div class="qi" style="background:#eff6ff">📄</div><span>Statement</span></button>\n        <button class="qa" onclick="go(\'investments\')">\n          <div class="qi" style="background:#f5f3ff">📈</div><span>Invest</span></button>\n      </div>\n      <div class="section-head">\n        <div class="sh-title">Recent Transactions</div>\n        <div class="sh-action" onclick="go(\'statement\')">See all →</div>\n      </div>\n      <div class="card" id="rxt"><div class="sp"></div></div>`;\n    loadRecent();\n  }catch(e){err_page(e.message);}\n}\n\nasync function loadRecent(){\n  try{\n    const d=await api(\'/api/me/statement?limit=5\');\n    const b=document.getElementById(\'rxt\');if(!b)return;\n    b.innerHTML=d.transactions.length\n      ?d.transactions.map(txRow).join(\'\')\n      :\'<div class="empty"><span class="empty-ic">📭</span><h3>No transactions yet</h3><p>Your transactions will appear here</p></div>\';\n  }catch(e){const b=document.getElementById(\'rxt\');if(b)b.innerHTML=`<p style="color:var(--muted);font-size:13px;text-align:center;padding:20px">${e.message}</p>`;}\n}\n\nfunction txRow(t){\n  const cr=t.type===\'deposit\';\n  const cls=cr?\'cr\':\'db\';\n  const ic=cr?\'⬆️\':\'⬇️\';\n  const sign=cr?\'+\':\'−\';\n  const amt=Math.abs(t.amount).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const bal=(t.balance||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const dt=t.date?new Date(t.date).toLocaleDateString(\'en-KE\',{day:\'numeric\',month:\'short\'}):\'\';\n  const ch=t.channel?` · ${t.channel}`:\'\';\n  return `<div class="txn"><div class="txn-ic ${cls}">${ic}</div>\n    <div class="txn-body"><div class="txn-desc">${t.description||t.type}</div>\n    <div class="txn-meta">${dt}${ch}</div></div>\n    <div class="txn-right"><div class="txn-amt ${cls}">${sign}${amt}</div>\n    <div class="txn-bal">Bal ${bal}</div></div></div>`;\n}\n\n// ── STATEMENT ─────────────────────────────────────────────────────────────────\nlet sOff=0;\nasync function statement(reset=true){\n  const c=document.getElementById(\'pc\');\n  if(reset){sOff=0;c.innerHTML=\'<div class="sp"></div>\';}\n  try{\n    const d=await api(`/api/me/statement?limit=20&offset=${sOff}`);\n    if(reset)c.innerHTML=`<div class="section-head" style="margin-bottom:14px;">\n      <div class="sh-title">📄 Statement</div>\n      <div class="chip">${ME?.account_no||\'\'}</div></div>\n      <div class="card" id="sl"></div>\n      <button id="lmb" class="preset" style="width:100%;text-align:center;padding:13px;margin-bottom:20px;border-radius:12px;"\n        onclick="statement(false)">Load more transactions</button>`;\n    const b=document.getElementById(\'sl\');\n    if(!d.transactions.length&&reset){\n      b.innerHTML=\'<div class="empty"><span class="empty-ic">📭</span><h3>No transactions yet</h3></div>\';\n      document.getElementById(\'lmb\').style.display=\'none\';return;}\n    b.innerHTML+=(d.transactions||[]).map(txRow).join(\'\');\n    sOff+=d.transactions.length;\n    if(d.transactions.length<20)document.getElementById(\'lmb\').style.display=\'none\';\n  }catch(e){err_page(e.message);}\n}\n\n// ── LOANS ─────────────────────────────────────────────────────────────────────\nasync function loans(){\n  const c=document.getElementById(\'pc\');c.innerHTML=\'<div class="sp"></div>\';\n  try{\n    const d=await api(\'/api/me/loans\');\n    const ls=d.loans||[];\n    c.innerHTML=`<div class="section-head" style="margin-bottom:14px;">\n      <div class="sh-title">💳 My Loans</div>\n      <button class="preset" style="color:var(--g)" onclick="openMo(\'loan-mo\')">+ Apply</button></div>\n      ${!ls.length\n        ?`<div class="empty"><span class="empty-ic">💳</span><h3>No loans yet</h3>\n           <p>You can apply for a loan anytime</p>\n           <button class="btn btn-g" style="width:auto;padding:12px 28px;margin-top:20px;border-radius:12px;"\n                   onclick="openMo(\'loan-mo\')">Apply for a Loan</button></div>`\n        :ls.map(lRow).join(\'\')}`;\n  }catch(e){err_page(e.message);}\n}\n\nfunction lRow(l){\n  const out=(l.outstanding||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const pri=(l.amount||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const ins=(l.installment||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const pct=l.amount>0?Math.round((1-l.outstanding/l.amount)*100):0;\n  const cls=l.status===\'overdue\'?\'overdue\':l.status===\'pending\'?\'pending\':\'\';\n  return `<div class="loan-card ${cls}">\n    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">\n      <div style="font-size:18px;font-weight:800;">KSh ${pri}</div>\n      <span class="badge ${l.status}">${l.status.replace(\'_\',\' \').toUpperCase()}</span></div>\n    <div class="prog"><div class="progf" style="width:${pct}%"></div></div>\n    <div style="font-size:11px;color:var(--muted);margin-bottom:10px">${pct}% repaid</div>\n    <div class="lrow"><span class="ll">Outstanding</span><span class="lv" style="color:var(--r)">KSh ${out}</span></div>\n    <div class="lrow"><span class="ll">Monthly installment</span><span class="lv">KSh ${ins}</span></div>\n    <div class="lrow"><span class="ll">Next due date</span><span class="lv">${l.next_due||\'—\'}</span></div>\n    ${l.purpose?`<div class="lrow"><span class="ll">Purpose</span><span class="lv">${l.purpose}</span></div>`:\'\'}\n  </div>`;\n}\n\nfunction calcLoan(){\n  const amt=parseFloat(document.getElementById(\'la\')?.value||0);\n  const term=parseInt(document.getElementById(\'lt\')?.value||12);\n  const rate=parseFloat(document.getElementById(\'lr\')?.value||1.5)/100;\n  const box=document.getElementById(\'lcalc\');\n  const sum=document.getElementById(\'lsum\');\n  if(amt>=1000&&term>=1&&box&&sum){\n    const mo=amt*rate*Math.pow(1+rate,term)/(Math.pow(1+rate,term)-1);\n    const total=mo*term;\n    const interest=total-amt;\n    box.style.display=\'block\';\n    sum.innerHTML=`Monthly installment: <strong>KSh ${mo.toLocaleString(\'en-KE\',{minimumFractionDigits:2})}</strong><br>\n      Total repayment: <strong>KSh ${total.toLocaleString(\'en-KE\',{minimumFractionDigits:2})}</strong><br>\n      Total interest: KSh ${interest.toLocaleString(\'en-KE\',{minimumFractionDigits:2})}`;\n  }else if(box){box.style.display=\'none\';}\n}\n\n// ── INVESTMENTS ───────────────────────────────────────────────────────────────\nasync function investments(){\n  const c=document.getElementById(\'pc\');c.innerHTML=\'<div class="sp"></div>\';\n  try{\n    const d=await api(\'/api/me/investments\');\n    const iv=d.investments||[];\n    c.innerHTML=`<div class="section-head" style="margin-bottom:14px;">\n      <div class="sh-title">📈 Investments</div></div>\n      ${!iv.length\n        ?`<div class="empty"><span class="empty-ic">📈</span><h3>No investments yet</h3>\n           <p>Visit any branch to open a Fixed Deposit or Unit Trust account.</p></div>`\n        :iv.map(iRow).join(\'\')}`;\n  }catch(e){err_page(e.message);}\n}\n\nfunction iRow(i){\n  const pr=(i.principal||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  const ie=(i.interest||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2});\n  return `<div class="card" style="border-left:4px solid ${i.status===\'active\'?\'var(--g)\':\'var(--muted)\'}">\n    <div style="display:flex;justify-content:space-between;margin-bottom:12px">\n      <div style="font-weight:800;font-size:16px">${i.name||i.type||\'Investment\'}</div>\n      <span class="badge ${i.status}">${i.status.toUpperCase()}</span></div>\n    <div class="lrow"><span class="ll">Principal</span><span class="lv">KSh ${pr}</span></div>\n    <div class="lrow"><span class="ll">Interest earned</span><span class="lv" style="color:var(--g)">KSh ${ie}</span></div>\n    <div class="lrow"><span class="ll">Rate</span><span class="lv">${i.rate}% p.a.</span></div>\n    <div class="lrow"><span class="ll">Matures</span><span class="lv">${i.maturity||\'—\'}</span></div>\n  </div>`;\n}\n\n// ── PROFILE ───────────────────────────────────────────────────────────────────\nasync function profile(){\n  const c=document.getElementById(\'pc\');c.innerHTML=\'<div class="sp"></div>\';\n  try{\n    await loadMe();const m=ME;\n    const init=(m.name||\'M\').split(\' \').map(w=>w[0]).join(\'\').slice(0,2).toUpperCase();\n    const kyc=m.kyc_status===\'verified\'?`<span class="kyc-v">✓ Verified</span>`:`<span class="kyc-p">⏳ ${m.kyc_status||\'Pending\'}</span>`;\n    c.innerHTML=`\n      <div class="card" style="text-align:center;padding:28px 18px;margin-bottom:14px">\n        <div class="pav">${init}</div>\n        <div style="font-size:20px;font-weight:800;margin-bottom:4px">${m.name||\'—\'}</div>\n        <div style="font-size:13px;color:var(--muted);margin-bottom:12px">Member No: ${m.member_no||\'—\'}</div>\n        ${kyc}\n      </div>\n      <div class="card">\n        <div class="card-title">Account Information</div>\n        <div class="info-row"><span class="il">Phone</span><span class="iv">${m.phone||\'—\'}</span></div>\n        <div class="info-row"><span class="il">Email</span><span class="iv">${m.email||\'—\'}</span></div>\n        <div class="info-row"><span class="il">Account No</span><span class="iv">${m.account_no||\'—\'}</span></div>\n        <div class="info-row"><span class="il">Balance</span>\n          <span class="iv" style="color:var(--g);font-size:18px;font-weight:800">\n          KSh ${(m.balance||0).toLocaleString(\'en-KE\',{minimumFractionDigits:2})}</span></div>\n        <div class="info-row"><span class="il">KYC Status</span><span class="iv">${kyc}</span></div>\n      </div>\n      <button class="btn" style="background:var(--r);color:#fff;border-radius:14px;margin-bottom:24px" onclick="doLogout()">Log Out</button>`;\n  }catch(e){err_page(e.message);}\n}\n\n// ── MODALS ────────────────────────────────────────────────────────────────────\nfunction openMo(id){\n  const m=document.getElementById(id);\n  m.style.display=\'flex\';setTimeout(()=>m.classList.add(\'open\'),10);\n}\nfunction closeMo(){\n  document.querySelectorAll(\'.mo\').forEach(m=>{\n    m.classList.remove(\'open\');setTimeout(()=>m.style.display=\'none\',300);\n  });\n}\ndocument.addEventListener(\'click\',e=>{\n  if(e.target.classList.contains(\'mo\'))closeMo();\n});\n\nfunction setAmt(btn,v){\n  document.getElementById(\'da\').value=v;\n  document.querySelectorAll(\'.preset\').forEach(b=>b.classList.remove(\'sel\'));\n  btn.classList.add(\'sel\');\n}\n\nasync function submitDeposit(){\n  const amount=parseFloat(document.getElementById(\'da\').value);\n  const phone=document.getElementById(\'dp\').value.trim();\n  if(!amount||amount<10){toast(\'Enter amount (minimum KSh 10)\',\'err\');return;}\n  if(!phone){toast(\'Enter your M-Pesa number\',\'err\');return;}\n  try{\n    const res=await api(\'/api/me/stk_deposit\',{method:\'POST\',body:JSON.stringify({amount,phone})});\n    closeMo();toast(\'✅ \'+(res.message||\'STK Push sent — check your phone!\'),\'ok\');\n    setTimeout(()=>home(),3500);\n  }catch(e){toast(\'❌ \'+e.message,\'err\');}\n}\n\nasync function submitLoan(){\n  const amount=parseFloat(document.getElementById(\'la\').value);\n  const term=parseInt(document.getElementById(\'lt\').value);\n  const purpose=document.getElementById(\'lpu\').value.trim();\n  if(!amount||amount<1000){toast(\'Minimum loan is KSh 1,000\',\'err\');return;}\n  if(!term||term<1||term>60){toast(\'Term must be 1–60 months\',\'err\');return;}\n  try{\n    const res=await api(\'/api/me/loan_apply\',{method:\'POST\',body:JSON.stringify({amount,term_months:term,purpose})});\n    closeMo();toast(\'✅ \'+res.message,\'ok\');\n    setTimeout(()=>loans(),1800);\n  }catch(e){toast(\'❌ \'+e.message,\'err\');}\n}\n\n// ── TOAST ─────────────────────────────────────────────────────────────────────\nfunction toast(msg,type=\'info\',ms=4000){\n  const el=document.getElementById(\'toast\');\n  el.textContent=msg;el.className=\'toast \'+type+\' show\';\n  clearTimeout(el._t);el._t=setTimeout(()=>el.classList.remove(\'show\'),ms);\n}\n\n// ── UTILS ─────────────────────────────────────────────────────────────────────\nfunction err_page(msg){\n  document.getElementById(\'pc\').innerHTML=`<div class="empty">\n    <span class="empty-ic">⚠️</span><h3>Something went wrong</h3><p>${msg}</p>\n    <button class="btn btn-g" style="width:auto;padding:12px 24px;margin-top:20px;border-radius:12px;"\n            onclick="loadMe().then(()=>go(\'home\')).catch(()=>doLogout())">Retry</button></div>`;\n}\n</script>\n</body>\n</html>'


def build_app(kivy_app):
    """FastAPI ASGI app - only used if fastapi is installed."""
    import hashlib, base64, json, datetime, os
    import hmac as _hmac, time as _time, uuid as _uuid
    from typing import Optional
    from server import sign_jwt, verify_jwt, _hash_pw, _norm_phone, _server_port

    from fastapi import FastAPI, HTTPException, Request
    from fastapi.responses import HTMLResponse
    from fastapi.middleware.cors import CORSMiddleware

    app = FastAPI(title="HELA SMART SACCO API", version="3.1",
                  docs_url=None, redoc_url=None)
    app.add_middleware(CORSMiddleware, allow_origins=["*"],
                       allow_methods=["*"], allow_headers=["*"])
    db = kivy_app.db

    def _auth(request):
        auth = request.headers.get("Authorization", "")
        if not auth.startswith("Bearer "):
            raise HTTPException(401, "Not authenticated")
        p = verify_jwt(auth[7:])
        if not p:
            raise HTTPException(401, "Token expired")
        return p

    def _mid(uid):
        row = db.fetch_one(
            "SELECT m.id FROM members m JOIN users u ON u.id=m.user_id WHERE u.id=?", (uid,))
        return (row or {}).get("id") or uid

    @app.post("/api/auth/login")
    async def login(request: Request):
        b = await request.json()
        phone, pw = str(b.get("phone","")).strip(), str(b.get("password","")).strip()
        if not phone or not pw:
            raise HTTPException(400, "Phone and password required")
        p = _norm_phone(phone)
        m = (db.fetch_one(
                "SELECT m.*, u.id as uid, u.password_hash, u.salt, u.iterations, u.role "
                "FROM members m JOIN users u ON u.id=m.user_id "
                "WHERE (m.phone=? OR m.phone=?) AND m.is_active=1", (phone, p))
             or db.fetch_one(
                "SELECT u.id as uid,u.id,u.username,u.password_hash,u.salt,u.iterations,u.role "
                "FROM users u WHERE u.username=? AND u.is_active=1", (phone,)))
        if not m: raise HTTPException(401, "Phone number or password is incorrect")
        h, _ = _hash_pw(pw, m["salt"], m["iterations"] or 600000)
        if h != m["password_hash"]: raise HTTPException(401, "Phone number or password is incorrect")
        uid  = m.get("uid") or m["id"]
        role = (m.get("role") or "member").lower()
        return {"token": sign_jwt({"sub": uid, "role": role}), "role": role,
                "name": m.get("full_name") or m.get("username","")}

    @app.post("/api/auth/register")
    async def register(request: Request):
        b = await request.json()
        first = str(b.get("first_name","")).strip()
        last  = str(b.get("last_name","")).strip()
        phone = str(b.get("phone","")).strip()
        id_no = str(b.get("id_number","")).strip()
        email = str(b.get("email","")).strip()
        pw    = str(b.get("password","")).strip()
        if not first or not last: raise HTTPException(400, "Full name required")
        if not phone:             raise HTTPException(400, "Phone number required")
        if not id_no:             raise HTTPException(400, "National ID required")
        if len(pw) < 6:           raise HTTPException(400, "Password must be at least 6 characters")
        p = _norm_phone(phone)
        if db.fetch_one("SELECT id FROM members WHERE phone=? OR phone=?", (phone, p)):
            raise HTTPException(409, "Phone number already registered")
        if db.fetch_one("SELECT id FROM members WHERE id_number=?", (id_no,)):
            raise HTTPException(409, "ID number already registered")
        now = datetime.datetime.now().isoformat()
        uid = str(_uuid.uuid4()); mid = str(_uuid.uuid4())
        full = f"{first} {last}"
        cnt  = (db.fetch_one("SELECT COUNT(*) as c FROM members") or {}).get("c",0)
        mno  = f"HLS{str(cnt+1).zfill(5)}"
        pw_hash, salt = _hash_pw(pw)
        db.execute("INSERT INTO users (id,username,password_hash,salt,iterations,role,full_name,is_active,created_at) VALUES (?,?,?,?,?,?,?,1,?)",
                   (uid,p,pw_hash,salt,600000,"member",full,now))
        db.execute("INSERT INTO members (id,user_id,member_no,first_name,last_name,full_name_search,phone,email,id_number,is_active,kyc_status,membership_date,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,1,'pending',date('now'),?,?)",
                   (mid,uid,mno,first,last,full.lower(),p,email,id_no,now,now))
        db.execute("INSERT INTO accounts (id,member_id,account_no,account_type,balance_minor,is_active,opening_date,created_at,updated_at) VALUES (?,?,?,'savings',0,1,date('now'),?,?)",
                   (str(_uuid.uuid4()),mid,f"SAV{mno[3:]}",now,now))
        return {"token": sign_jwt({"sub": uid,"role":"member"}), "role":"member",
                "name": full, "member_no": mno,
                "message":"Account created! Visit a branch to complete KYC."}

    @app.get("/api/me")
    async def get_me(request: Request):
        u = _auth(request); uid = u["sub"]
        m = (db.fetch_one("SELECT m.*,u.username,u.role FROM members m JOIN users u ON u.id=m.user_id WHERE u.id=?",(uid,))
             or db.fetch_one("SELECT id,username,role FROM users WHERE id=?",(uid,)))
        if not m: raise HTTPException(404,"Member not found")
        mid = m.get("id") or uid
        acc = db.fetch_one("SELECT * FROM accounts WHERE member_id=? AND account_type='savings' LIMIT 1",(mid,))
        loans = db.fetch_all("SELECT id,principal_minor,outstanding_balance_minor,status,next_due_date,monthly_installment_minor FROM loans WHERE member_id=? AND status IN ('active','disbursed','overdue') ORDER BY created_at DESC",(mid,))
        return {"id":mid,"name":m.get("full_name") or m.get("username",""),
                "member_no":m.get("member_no",""),"phone":m.get("phone",""),
                "email":m.get("email",""),"kyc_status":m.get("kyc_status","pending"),
                "balance":(acc or {}).get("balance_minor",0)/100,
                "account_no":(acc or {}).get("account_no",""),
                "account_id":(acc or {}).get("id",""),
                "loans":[{"id":l["id"],"principal":l["principal_minor"]/100,
                           "outstanding":l["outstanding_balance_minor"]/100,
                           "status":l["status"],"next_due":str(l.get("next_due_date","") or ""),
                           "installment":l.get("monthly_installment_minor",0)/100} for l in loans]}

    @app.get("/api/me/statement")
    async def statement(request: Request, limit:int=30, offset:int=0):
        u=_auth(request); mid=_mid(u["sub"])
        txns=db.fetch_all("SELECT t.*,a.account_no FROM transactions t JOIN accounts a ON a.id=t.account_id WHERE a.member_id=? ORDER BY t.created_at DESC LIMIT ? OFFSET ?",(mid,min(limit,100),offset))
        return {"transactions":[{"id":t["id"],"type":t["transaction_type"],"amount":t["amount_minor"]/100,"balance":t.get("balance_after_minor",0)/100,"description":t.get("description",""),"channel":t.get("channel",""),"date":str(t.get("created_at","")),"reference":t.get("reference_number","")} for t in txns]}

    @app.get("/api/me/loans")
    async def get_loans(request: Request):
        u=_auth(request); mid=_mid(u["sub"])
        loans=db.fetch_all("SELECT * FROM loans WHERE member_id=? ORDER BY created_at DESC",(mid,))
        return {"loans":[{"id":l["id"],"amount":l["principal_minor"]/100,"outstanding":l.get("outstanding_balance_minor",0)/100,"status":l["status"],"next_due":str(l.get("next_due_date","") or ""),"installment":l.get("monthly_installment_minor",0)/100,"term_months":l.get("term_months",0),"interest_rate":l.get("interest_rate",0),"purpose":l.get("loan_purpose","")} for l in loans]}

    @app.get("/api/me/investments")
    async def get_investments(request: Request):
        u=_auth(request); mid=_mid(u["sub"])
        invs=db.fetch_all("SELECT * FROM investments WHERE member_id=? ORDER BY created_at DESC",(mid,))
        return {"investments":[{"id":i["id"],"name":i.get("name",""),"type":i.get("investment_type",""),"principal":i["principal_minor"]/100,"interest":i.get("interest_earned_minor",0)/100,"rate":i.get("interest_rate",0),"start":str(i.get("start_date","")),"maturity":str(i.get("maturity_date","")),"status":i.get("status","")} for i in invs]}

    @app.post("/api/me/loan_apply")
    async def loan_apply(request: Request):
        u=_auth(request); mid=_mid(u["sub"]); b=await request.json()
        amt=float(b.get("amount",0)); term=int(b.get("term_months",12))
        purpose=str(b.get("purpose","Personal")).strip()
        if amt<1000: raise HTTPException(400,"Minimum loan is KSh 1,000")
        if not(1<=term<=60): raise HTTPException(400,"Term must be 1-60 months")
        lid=str(_uuid.uuid4()); now=datetime.datetime.now().isoformat()
        db.execute("INSERT INTO loans (id,member_id,principal_minor,term_months,loan_purpose,status,created_at,updated_at) VALUES (?,?,?,?,?,'pending',?,?)",(lid,mid,int(amt*100),term,purpose,now,now))
        return {"status":"submitted","loan_id":lid,"message":"Application submitted. We will contact you within 24 hours."}

    @app.post("/api/me/stk_deposit")
    async def stk_deposit(request: Request):
        u=_auth(request); mid=_mid(u["sub"]); b=await request.json()
        amt=float(b.get("amount",0)); phone=str(b.get("phone","")).strip()
        if amt<10: raise HTTPException(400,"Minimum deposit is KSh 10")
        if not phone: raise HTTPException(400,"Phone number required")
        acc=db.fetch_one("SELECT * FROM accounts WHERE member_id=? AND account_type='savings' LIMIT 1",(mid,))
        if not acc: raise HTTPException(404,"No savings account found")
        res=kivy_app.mobile_money_service.receive_stk_push(phone=phone,amount_ksh=amt,account_ref=acc.get("account_no",mid[:10]),description="HELA SACCO Deposit",account_id=acc["id"],member_id=mid)
        if res.get("status") not in ("pending","success"): raise HTTPException(400,res.get("message","STK Push failed"))
        return {"status":"pending","message":res.get("message","Check your phone"),"checkout_id":res.get("checkout_id","")}

    @app.post("/mpesa/stk_callback")
    async def stk_cb(request: Request):
        try:
            body=await request.json()
            res=kivy_app.mobile_money_service.mpesa.parse_stk_callback(body)
            cid=res.get("checkout_id","")
            if res.get("status")=="success":
                tx=db.fetch_one("SELECT * FROM mobile_money_transactions WHERE conversation_id=? AND direction='inbound' AND status='pending' LIMIT 1",(cid,))
                if tx and tx.get("account_id"):
                    kivy_app.account_service.post_transaction(tx["account_id"],"deposit",int(round(res.get("amount",0)*100)),"M-Pesa STK deposit",channel="mobile_money",reference_number=res.get("mpesa_receipt",""))
                    db.execute("UPDATE mobile_money_transactions SET status='completed',mpesa_transaction_id=? WHERE conversation_id=?",(res.get("mpesa_receipt",""),cid))
        except Exception as e:
            pass
        return {"ResultCode":0,"ResultDesc":"Accepted"}

    @app.post("/mpesa/b2c_callback")
    async def b2c_cb(request: Request):
        try:
            body=await request.json(); result=body.get("Result",{})
            params={p["Key"]:p["Value"] for p in result.get("ResultParameters",{}).get("ResultParameter",[])}
            cid=result.get("ConversationID","")
            db.execute("UPDATE mobile_money_transactions SET status=?,mpesa_transaction_id=? WHERE conversation_id=?",("completed" if result.get("ResultCode",1)==0 else "failed",params.get("TransactionReceipt",""),cid))
        except: pass
        return {"ResultCode":0,"ResultDesc":"Accepted"}

    @app.get("/{full_path:path}", response_class=HTMLResponse)
    async def spa(full_path: str):
        return HTMLResponse(PORTAL_HTML)

    @app.get("/", response_class=HTMLResponse)
    async def root():
        return HTMLResponse(PORTAL_HTML)

    return app
